class Solution:
    def primePalindrome(self, n: int) -> int:
        def is_prime(num):
            if num <= 1:
                return False
            for i in range(2, int(num**0.5) + 1):
                if num % i == 0:
                    return False
            return True

        while True:
            num = n
            if num > 1:
                s = str(num)
                if s == s[::-1] and is_prime(num):
                    return num
            num += 1 
